mapper.select:
select id, asset_code assetCode, asset_name assetName, asset_typeid assetTypeid, asset_typename assetTypename, spe_model speModel, manufacturer, purchase_date purchaseDate, orig_value origValue, service_life serviceLife, dep_id depId, dep_name depName, sto_location stoLocation, resp_person respPerson, asset_state assetState, depr_method deprMethod, serial_num serialNum, asset_desc assetDesc, attachment, cdate, udate FROM asset WHERE 1=1
AND asset_code LIKE concat('%', #{assetCode},'%')
AND asset_name LIKE concat('%', #{assetName},'%')
AND asset_state =#{assetState}
AND dep_id =#{depId}
AND asset_typeid =#{assetTypeid}
AND purchase_date >=#{purchaseStart} and purchase_date <= #{purchaseEnd}
